{
  "name": "agent-context-governor",
  "version": "0.1.0",
  "description": "Open-source runtime library for reducing token usage in coding-agent workflows.",
  "type": "module",
  "main": "./dist/src/index.js",
  "types": "./dist/src/index.d.ts",
  "exports": {
    ".": {
      "types": "./dist/src/index.d.ts",
      "import": "./dist/src/index.js"
    }
  },
  "bin": {
    "acg": "./dist/src/cli.js"
  },
  "files": [
    "dist"
  ],
  "scripts": {
    "build": "tsc -p tsconfig.json",
    "check": "tsc --noEmit -p tsconfig.json",
    "lint": "eslint .",
    "demo": "node ./dist/src/cli.js demo",
    "bench": "node ./dist/src/cli.js bench",
    "compare:claude": "node ./dist/src/cli.js compare-claude ./examples/sample-session.json",
    "prepare": "npm run build",
    "pretest": "npm run build",
    "test": "node --test dist/test"
  },
  "keywords": [
    "agents",
    "llm",
    "tokens",
    "context",
    "optimization"
  ],
  "author": "Glauco Jr Carvalho",
  "repository": {
    "type": "git",
    "url": "git+ssh://git@github.com/glaucojrcarvalho/agent-context-governor.git"
  },
  "bugs": {
    "url": "https://github.com/glaucojrcarvalho/agent-context-governor/issues"
  },
  "homepage": "https://github.com/glaucojrcarvalho/agent-context-governor#readme",
  "engines": {
    "node": ">=20"
  },
  "license": "MIT",
  "devDependencies": {
    "@eslint/js": "^9.25.1",
    "@types/node": "^20.17.30",
    "eslint": "^9.25.1",
    "typescript": "^5.8.3"
  }
}

import js from '@eslint/js'

export default [
  {
    ignores: [
      'dist/**',
      'node_modules/**',
      'coverage/**',
    ],
  },
  js.configs.recommended,
  {
    files: ['src/**/*.js', 'test/**/*.js'],
    languageOptions: {
      ecmaVersion: 'latest',
      sourceType: 'module',
    },
  },
]

#!/usr/bin/env node

import { resolve } from 'node:path'

import { runBenchmarks, runScenario } from './benchmark.js'
import { runClaudeBenchmark, runClaudeReviewComparison } from './claude.js'
import { getDefaultScenarios } from './fixtures.js'
import { buildRepoReviewImportOptions, writeImportedScenario } from './importer.js'
import { parseScenarioFile } from './input.js'
import { writeClaudeReviewReport } from './report.js'

function formatPercent(value: number): string {
  return `${(value * 100).toFixed(1)}%`
}

function formatScenarioList(): string {
  return getDefaultScenarios()
    .map(scenario => `- ${scenario.id}: ${scenario.title}`)
    .join('\n')
}

function formatBenchmarkOutput(): string {
  const results = runBenchmarks(getDefaultScenarios())

  return results
    .map(result => {
      const lines = [
        `Scenario: ${result.scenarioTitle}`,
        `Baseline tokens: ${result.baselineTokens}`,
        `Optimized tokens: ${result.optimizedTokens}`,
        `Saved tokens: ${result.savedTokens} (${formatPercent(result.savingsRatio)})`,
        'Decisions:',
        ...result.decisions.map(
          decision => `- ${decision.type} ${decision.candidateId}: ${decision.reason}`,
        ),
      ]

      return lines.join('\n')
    })
    .join('\n\n')
}

function formatSingleScenario(id: string): string {
  const scenario = getDefaultScenarios().find(item => item.id === id)
  if (!scenario) {
    return [
      `Unknown scenario: ${id}`,
      'Available scenarios:',
      formatScenarioList(),
    ].join('\n')
  }

  const result = runScenario(scenario)
  return [
    `Scenario: ${result.scenarioTitle}`,
    `Baseline tokens: ${result.baselineTokens}`,
    `Optimized tokens: ${result.optimizedTokens}`,
    `Saved tokens: ${result.savedTokens} (${formatPercent(result.savingsRatio)})`,
    'Final context:',
    ...result.finalContext.map(line => `- ${line}`),
    'Decisions:',
    ...result.decisions.map(
      decision => `- ${decision.type} ${decision.candidateId}: ${decision.reason}`,
    ),
  ].join('\n')
}

function formatScenarioResult(result: ReturnType<typeof runScenario>): string {
  return [
    `Scenario: ${result.scenarioTitle}`,
    `Baseline tokens: ${result.baselineTokens}`,
    `Optimized tokens: ${result.optimizedTokens}`,
    `Saved tokens: ${result.savedTokens} (${formatPercent(result.savingsRatio)})`,
    'Final context:',
    ...result.finalContext.map(line => `- ${line}`),
    'Decisions:',
    ...result.decisions.map(
      decision => `- ${decision.type} ${decision.candidateId}: ${decision.reason}`,
    ),
  ].join('\n')
}

function formatFileScenario(filePath: string): string {
  const scenario = parseScenarioFile(resolve(filePath))
  const result = runScenario(scenario)
  return formatScenarioResult(result)
}

function formatClaudeComparison(filePath: string): string {
  const scenario = parseScenarioFile(resolve(filePath))
  const result = runClaudeBenchmark(scenario, {
    permissionMode: 'bypassPermissions',
  })

  return [
    `Scenario: ${scenario.title}`,
    `Claude baseline input tokens: ${result.baseline.inputTokens}`,
    `Claude optimized input tokens: ${result.optimized.inputTokens}`,
    `Saved input tokens: ${result.savedInputTokens}`,
    `Claude baseline cache creation tokens: ${result.baseline.cacheCreationInputTokens}`,
    `Claude optimized cache creation tokens: ${result.optimized.cacheCreationInputTokens}`,
    `Saved cache creation tokens: ${result.savedCacheCreationTokens}`,
    `Claude baseline cache read tokens: ${result.baseline.cacheReadInputTokens}`,
    `Claude optimized cache read tokens: ${result.optimized.cacheReadInputTokens}`,
    `Saved cache read tokens: ${result.savedCacheReadTokens}`,
    `Saved total tokens: ${result.savedTotalTokens}`,
    `Baseline output tokens: ${result.baseline.outputTokens}`,
    `Optimized output tokens: ${result.optimized.outputTokens}`,
    `Baseline cost USD: ${result.baseline.totalCostUsd ?? 'unknown'}`,
    `Optimized cost USD: ${result.optimized.totalCostUsd ?? 'unknown'}`,
  ].join('\n')
}

function formatClaudeReviewComparison(filePath: string): string {
  const scenario = parseScenarioFile(resolve(filePath))
  const result = runClaudeReviewComparison(scenario, {
    permissionMode: 'bypassPermissions',
  })

  return [
    `Scenario: ${scenario.title}`,
    `Saved input tokens: ${result.savedInputTokens}`,
    `Saved cache creation tokens: ${result.savedCacheCreationTokens}`,
    `Saved cache read tokens: ${result.savedCacheReadTokens}`,
    `Saved total tokens: ${result.savedTotalTokens}`,
    '',
    'Baseline review:',
    result.baseline.rawResult || '(empty)',
    '',
    'Optimized review:',
    result.optimized.rawResult || '(empty)',
  ].join('\n')
}

function getFlagValues(argv: string[], flag: string): string[] {
  const values: string[] = []
  for (let i = 0; i < argv.length; i++) {
    if (argv[i] === flag) {
      const value = argv[i + 1]
      if (value && !value.startsWith('--')) {
        values.push(value)
      }
    }
  }
  return values
}

function getFlagValue(argv: string[], flag: string): string | undefined {
  return getFlagValues(argv, flag)[0]
}

function formatImportedScenario(argv: string[]): string {
  const objective = getFlagValue(argv, '--objective')
  if (!objective) {
    throw new Error('Missing required flag: --objective')
  }

  const title = getFlagValue(argv, '--title') ?? 'Imported Scenario'
  const outFile = getFlagValue(argv, '--out') ?? './acg-session.json'
  const searchRoot = getFlagValue(argv, '--search-root') ?? '.'
  const softLimitTokens = Number(getFlagValue(argv, '--soft-limit') ?? '4000')
  const hardLimitTokens = Number(getFlagValue(argv, '--hard-limit') ?? '6000')
  const readPaths = getFlagValues(argv, '--read')
  const logPaths = getFlagValues(argv, '--log')
  const searchPatterns = getFlagValues(argv, '--search')

  const scenario = writeImportedScenario({
    title,
    objective,
    outFile,
    softLimitTokens,
    hardLimitTokens,
    readPaths,
    logPaths,
    searchPatterns,
    searchRoot,
  })

  return [
    `Wrote scenario: ${outFile}`,
    `Title: ${scenario.title}`,
    `Candidates: ${scenario.candidates.length}`,
    `Budget: soft=${scenario.budget.softLimitTokens} hard=${scenario.budget.hardLimitTokens}`,
  ].join('\n')
}

function formatRepoReviewScenario(argv: string[]): string {
  const rootDir = getFlagValue(argv, '--root') ?? '.'
  const title = getFlagValue(argv, '--title')
  const objective = getFlagValue(argv, '--objective')
  const outFile = getFlagValue(argv, '--out')
  const softLimitTokens = Number(getFlagValue(argv, '--soft-limit') ?? '2600')
  const hardLimitTokens = Number(getFlagValue(argv, '--hard-limit') ?? '3600')

  const scenario = writeImportedScenario(
    buildRepoReviewImportOptions({
      rootDir,
      title,
      objective,
      outFile,
      softLimitTokens,
      hardLimitTokens,
    }),
  )

  return [
    `Wrote scenario: ${resolve(rootDir, outFile ?? './acg-repo-review.json')}`,
    `Title: ${scenario.title}`,
    `Candidates: ${scenario.candidates.length}`,
    `Budget: soft=${scenario.budget.softLimitTokens} hard=${scenario.budget.hardLimitTokens}`,
  ].join('\n')
}

function formatReviewReport(argv: string[]): string {
  const filePath = argv[1]
  if (!filePath) {
    throw new Error('Missing scenario file path.')
  }

  const outFile = getFlagValue(argv, '--out') ?? './review-report.md'
  writeClaudeReviewReport(resolve(filePath), resolve(outFile))

  return [
    `Wrote report: ${outFile}`,
    `Scenario: ${filePath}`,
  ].join('\n')
}

function printHelp(): string {
  return [
    'Agent Context Governor CLI',
    '',
    'Usage:',
    '  acg help',
    '  acg list',
    '  acg demo',
    '  acg bench',
    '  acg scenario <id>',
    '  acg run <scenario.json>',
    '  acg compare-claude <scenario.json>',
    '  acg import --objective <text> [options]',
    '  acg import-review [--root <dir>] [options]',
    '  acg review-claude <scenario.json>',
    '  acg review-report <scenario.json> [--out <file>]',
    '',
    'Commands:',
    '  help       Show this help text',
    '  list       List built-in benchmark scenarios',
    '  demo       Run the default demo output',
    '  bench      Run all built-in benchmark scenarios',
    '  scenario   Run one built-in scenario by id',
    '  run        Run a custom scenario from a JSON file',
    '  compare-claude  Benchmark raw vs optimized context with real Claude usage',
    '  import     Build a scenario JSON from real files, logs, and search results',
    '  import-review   Build a repo-review scenario from common project files automatically',
    '  review-claude   Run a real Claude review with raw and optimized context',
    '  review-report   Save a markdown report for the raw vs optimized Claude review',
  ].join('\n')
}

function main(argv: string[]): void {
  const [, , command = 'help', arg] = argv

  switch (command) {
    case 'help':
      console.log(printHelp())
      return
    case 'list':
      console.log(formatScenarioList())
      return
    case 'demo':
    case 'bench':
      console.log(formatBenchmarkOutput())
      return
    case 'scenario':
      if (!arg) {
        console.log('Missing scenario id.\n')
        console.log(formatScenarioList())
        return
      }
      console.log(formatSingleScenario(arg))
      return
    case 'run':
      if (!arg) {
        console.log('Missing scenario file path.\n')
        console.log('Example: acg run ./examples/sample-session.json')
        return
      }
      console.log(formatFileScenario(arg))
      return
    case 'compare-claude':
      if (!arg) {
        console.log('Missing scenario file path.\n')
        console.log('Example: acg compare-claude ./examples/sample-session.json')
        return
      }
      console.log(formatClaudeComparison(arg))
      return
    case 'review-claude':
      if (!arg) {
        console.log('Missing scenario file path.\n')
        console.log('Example: acg review-claude ./examples/sample-session.json')
        return
      }
      console.log(formatClaudeReviewComparison(arg))
      return
    case 'import':
      console.log(formatImportedScenario(argv.slice(2)))
      return
    case 'import-review':
      console.log(formatRepoReviewScenario(argv.slice(2)))
      return
    case 'review-report':
      console.log(formatReviewReport(argv.slice(2)))
      return
    default:
      console.log(`Unknown command: ${command}\n`)
      console.log(printHelp())
  }
}

try {
  main(process.argv)
} catch (error) {
  const message = error instanceof Error ? error.message : String(error)
  console.error(`Error: ${message}`)
  process.exit(1)
}

import { ContextBudgetPolicy } from './budget-policy.js'
import { DEFAULT_GOVERNOR_CONFIG, mergeGovernorConfig, type GovernorConfig } from './config.js'
import {
  compareCandidates,
  evaluateCandidate,
  toDecision,
} from './rules.js'
import { SavingsReporter } from './savings-reporter.js'
import type {
  GovernorInput,
  GovernorResult,
  OptimizationDecision,
} from './types.js'

export class ContextGovernor {
  constructor(private readonly config: GovernorConfig = DEFAULT_GOVERNOR_CONFIG) {}

  optimize(input: GovernorInput): GovernorResult {
    const effectiveConfig = mergeGovernorConfig({
      ...this.config,
      budget: input.budget,
    })
    const policy = new ContextBudgetPolicy(effectiveConfig.budget)
    const reporter = new SavingsReporter()
    const baselineTokens = policy.sumTokens(input.candidates)
    const decisions: OptimizationDecision[] = []

    const ordered = [...input.candidates].sort((left, right) =>
      compareCandidates(left, right, effectiveConfig),
    )

    let runningTokens = 0
    const finalContext: string[] = []

    for (const candidate of ordered) {
      const action = evaluateCandidate(candidate, {
        softLimitTokens: effectiveConfig.budget.softLimitTokens,
        hardLimitTokens: effectiveConfig.budget.hardLimitTokens,
        runningTokens,
        config: effectiveConfig,
      })

      if (action.type === 'keep') {
        finalContext.push(candidate.content)
        runningTokens += action.tokenCost
        decisions.push(toDecision(candidate.id, action))
        continue
      }

      if (action.type === 'replace') {
        finalContext.push(action.replacement)
        runningTokens += action.tokenCost
        decisions.push(toDecision(candidate.id, action))
        continue
      }

      decisions.push(toDecision(candidate.id, action))
    }

    const report = reporter.createReport(baselineTokens, runningTokens)

    return {
      finalContext,
      decisions,
      baselineTokens: report.baselineTokens,
      optimizedTokens: report.optimizedTokens,
    }
  }
}

import type {
  ContextCandidate,
  ContextCandidatePriority,
  OptimizationDecision,
} from './types.js'
import type { GovernorConfig } from './config.js'

export type RuleContext = {
  softLimitTokens: number
  hardLimitTokens: number
  runningTokens: number
  config: GovernorConfig
}

export type RuleAction =
  | {
      type: 'keep'
      tokenCost: number
      reason: string
    }
  | {
      type: 'replace'
      tokenCost: number
      replacement: string
      reason: string
    }
  | {
      type: 'drop'
      reason: string
    }

export function compareCandidates(
  left: ContextCandidate,
  right: ContextCandidate,
  config: GovernorConfig,
): number {
  const leftProtected = isProtectedSource(left, config)
  const rightProtected = isProtectedSource(right, config)
  if (leftProtected !== rightProtected) {
    return rightProtected ? 1 : -1
  }

  const priorityDelta =
    config.priority.scores[right.priority] - config.priority.scores[left.priority]
  if (priorityDelta !== 0) return priorityDelta
  return left.tokenEstimate - right.tokenEstimate
}

function getSource(candidate: ContextCandidate): string {
  return typeof candidate.metadata?.source === 'string'
    ? candidate.metadata.source
    : candidate.id
}

export function isProtectedSource(
  candidate: ContextCandidate,
  config: GovernorConfig,
): boolean {
  const source = getSource(candidate)
  return (config.protectedSources ?? []).some(pattern =>
    source.includes(pattern),
  )
}

export function getReplacementTokenCost(
  candidate: ContextCandidate,
  config: GovernorConfig,
): number {
  return config.replacement.tokenCosts[candidate.kind] ?? 24
}

export function buildReplacement(candidate: ContextCandidate): string {
  const source =
    typeof candidate.metadata?.source === 'string'
      ? candidate.metadata.source
      : candidate.id

  switch (candidate.kind) {
    case 'file_read':
      return `[file_read] ${source} was read earlier. Keep only exported symbols, key functions, and the active section.`
    case 'search_result':
      return `[search_result] ${source} produced prior matches. Keep only matched files and the most relevant hit clusters.`
    case 'shell_output':
      return `[shell_output] ${source} generated a log earlier. Keep only failing command, exit status, and top actionable lines.`
    case 'diagnostic':
      return `[diagnostic] ${source} had prior diagnostics. Keep only unresolved errors and affected files.`
    case 'web_content':
      return `[web_content] ${source} was fetched earlier. Keep only the summary and any quoted constraints already extracted.`
    case 'transcript_snapshot':
      return `[transcript_snapshot] ${source} was summarized earlier. Keep only the current task state and unresolved decisions.`
    default:
      return `[${candidate.kind}] compact reference for ${source}`
  }
}

export function shouldReplace(
  candidate: ContextCandidate,
  config: GovernorConfig,
): boolean {
  if (candidate.priority === 'critical' || candidate.priority === 'high') {
    return false
  }

  return config.replacement.enabledKinds.includes(candidate.kind)
}

export function evaluateCandidate(
  candidate: ContextCandidate,
  context: RuleContext,
): RuleAction {
  if (candidate.priority === 'critical') {
    const nextTotal = context.runningTokens + candidate.tokenEstimate
    if (nextTotal <= context.hardLimitTokens) {
      return {
        type: 'keep',
        tokenCost: candidate.tokenEstimate,
        reason: 'critical task context',
      }
    }
  }

  if (isProtectedSource(candidate, context.config)) {
    const nextTotal = context.runningTokens + candidate.tokenEstimate
    if (nextTotal <= context.hardLimitTokens) {
      return {
        type: 'keep',
        tokenCost: candidate.tokenEstimate,
        reason: 'protected review-critical context',
      }
    }
  }

  const nextTotal = context.runningTokens + candidate.tokenEstimate

  if (nextTotal <= context.softLimitTokens) {
    return {
      type: 'keep',
      tokenCost: candidate.tokenEstimate,
      reason: 'within soft budget',
    }
  }

  if (shouldReplace(candidate, context.config)) {
    const replacement = buildReplacement(candidate)
    const replacementCost = getReplacementTokenCost(candidate, context.config)
    const replacementTotal = context.runningTokens + replacementCost

    if (replacementTotal <= context.hardLimitTokens) {
      return {
        type: 'replace',
        tokenCost: replacementCost,
        replacement,
        reason:
          candidate.priority === 'critical' || candidate.priority === 'high'
            ? 'preserve important context in compact form'
            : 'compressed bulky context to stay within budget',
      }
    }
  }

  return {
    type: 'drop',
    reason: 'exceeds budget and has low replacement priority',
  }
}

export function toDecision(
  candidateId: string,
  action: RuleAction,
): OptimizationDecision {
  if (action.type === 'keep') {
    return {
      type: 'keep',
      candidateId,
      reason: action.reason,
    }
  }

  if (action.type === 'replace') {
    return {
      type: 'replace',
      candidateId,
      replacement: action.replacement,
      reason: action.reason,
    }
  }

  return {
    type: 'drop',
    candidateId,
    reason: action.reason,
  }
}

import type { ContextArtifactKind, ContextBudget, ContextCandidatePriority } from './types.js'

export type ReplacementConfig = {
  enabledKinds: ContextArtifactKind[]
  tokenCosts: Partial<Record<ContextArtifactKind, number>>
}

export type PriorityConfig = {
  scores: Record<ContextCandidatePriority, number>
}

export type GovernorConfig = {
  budget: ContextBudget
  replacement: ReplacementConfig
  priority: PriorityConfig
  protectedSources?: string[]
}

export const DEFAULT_GOVERNOR_CONFIG: GovernorConfig = {
  budget: {
    softLimitTokens: 1000,
    hardLimitTokens: 1200,
  },
  replacement: {
    enabledKinds: [
      'file_read',
      'search_result',
      'shell_output',
      'diagnostic',
      'transcript_snapshot',
    ],
    tokenCosts: {
      file_read: 36,
      search_result: 28,
      shell_output: 32,
      diagnostic: 24,
      web_content: 40,
      transcript_snapshot: 22,
      other: 24,
    },
  },
  priority: {
    scores: {
      critical: 4,
      high: 3,
      medium: 2,
      low: 1,
    },
  },
  protectedSources: [
    'README.md',
    'package.json',
    'SECURITY.md',
    'CONTRIBUTING.md',
    '.github/',
    '.gitignore',
    'eslint.config.js',
    'docs/architecture.md',
    'src/context-governor.ts',
    'src/cli.ts',
    'src/claude.ts',
  ],
}

export function mergeGovernorConfig(
  override?: Partial<GovernorConfig>,
): GovernorConfig {
  if (!override) {
    return DEFAULT_GOVERNOR_CONFIG
  }

  return {
    budget: {
      softLimitTokens:
        override.budget?.softLimitTokens ??
        DEFAULT_GOVERNOR_CONFIG.budget.softLimitTokens,
      hardLimitTokens:
        override.budget?.hardLimitTokens ??
        DEFAULT_GOVERNOR_CONFIG.budget.hardLimitTokens,
    },
    replacement: {
      enabledKinds:
        override.replacement?.enabledKinds ??
        DEFAULT_GOVERNOR_CONFIG.replacement.enabledKinds,
      tokenCosts: {
        ...DEFAULT_GOVERNOR_CONFIG.replacement.tokenCosts,
        ...override.replacement?.tokenCosts,
      },
    },
    priority: {
      scores: {
        ...DEFAULT_GOVERNOR_CONFIG.priority.scores,
        ...override.priority?.scores,
      },
    },
    protectedSources:
      override.protectedSources ?? DEFAULT_GOVERNOR_CONFIG.protectedSources,
  }
}

import { readFileSync } from 'node:fs'

import type {
  BenchmarkScenario,
  ContextArtifactKind,
  ContextCandidatePriority,
  InputCandidate,
  InputScenario,
} from './types.js'

const VALID_KINDS: ContextArtifactKind[] = [
  'file_read',
  'search_result',
  'shell_output',
  'diagnostic',
  'web_content',
  'transcript_snapshot',
  'other',
]

const VALID_PRIORITIES: ContextCandidatePriority[] = [
  'critical',
  'high',
  'medium',
  'low',
]

export function estimateTokens(text: string): number {
  const normalized = text.trim()
  if (normalized.length === 0) return 0
  return Math.ceil(normalized.length / 4)
}

function assertString(value: unknown, field: string): string {
  if (typeof value !== 'string' || value.trim() === '') {
    throw new Error(`Invalid "${field}": expected non-empty string`)
  }
  return value
}

function assertObject(value: unknown, field: string): Record<string, unknown> {
  if (typeof value !== 'object' || value === null || Array.isArray(value)) {
    throw new Error(`Invalid "${field}": expected object`)
  }
  return value as Record<string, unknown>
}

function normalizeCandidate(
  candidate: unknown,
  index: number,
): BenchmarkScenario['candidates'][number] {
  const data = assertObject(candidate, `candidates[${index}]`)
  const id = assertString(data.id, `candidates[${index}].id`)
  const kind = assertString(data.kind, `candidates[${index}].kind`)
  const priority = assertString(
    data.priority,
    `candidates[${index}].priority`,
  )
  const content = assertString(data.content, `candidates[${index}].content`)

  if (!VALID_KINDS.includes(kind as ContextArtifactKind)) {
    throw new Error(`Invalid "${id}.kind": expected one of ${VALID_KINDS.join(', ')}`)
  }

  if (!VALID_PRIORITIES.includes(priority as ContextCandidatePriority)) {
    throw new Error(
      `Invalid "${id}.priority": expected one of ${VALID_PRIORITIES.join(', ')}`,
    )
  }

  const inputCandidate = data as unknown as InputCandidate
  const tokenEstimate =
    typeof inputCandidate.tokenEstimate === 'number'
      ? inputCandidate.tokenEstimate
      : estimateTokens(content)

  return {
    id,
    kind: kind as ContextArtifactKind,
    priority: priority as ContextCandidatePriority,
    content,
    tokenEstimate,
    artifactId:
      typeof inputCandidate.artifactId === 'string'
        ? inputCandidate.artifactId
        : undefined,
    metadata:
      typeof inputCandidate.metadata === 'object' &&
      inputCandidate.metadata !== null &&
      !Array.isArray(inputCandidate.metadata)
        ? inputCandidate.metadata
        : undefined,
  }
}

export function parseScenarioFile(filePath: string): BenchmarkScenario {
  const raw = readFileSync(filePath, 'utf8')
  const parsed = JSON.parse(raw) as InputScenario
  const data = assertObject(parsed, 'root')
  const budget = assertObject(data.budget, 'budget')

  const softLimitTokens = budget.softLimitTokens
  const hardLimitTokens = budget.hardLimitTokens

  if (
    typeof softLimitTokens !== 'number' ||
    typeof hardLimitTokens !== 'number' ||
    softLimitTokens <= 0 ||
    hardLimitTokens <= 0
  ) {
    throw new Error(
      'Invalid "budget": expected positive numeric softLimitTokens and hardLimitTokens',
    )
  }

  if (hardLimitTokens < softLimitTokens) {
    throw new Error(
      'Invalid "budget": hardLimitTokens must be greater than or equal to softLimitTokens',
    )
  }

  if (!Array.isArray(data.candidates) || data.candidates.length === 0) {
    throw new Error('Invalid "candidates": expected a non-empty array')
  }

  return {
    id:
      typeof data.id === 'string' && data.id.trim() !== ''
        ? data.id
        : 'custom-scenario',
    title:
      typeof data.title === 'string' && data.title.trim() !== ''
        ? data.title
        : 'Custom Scenario',
    description:
      typeof data.description === 'string' ? data.description : '',
    budget: {
      softLimitTokens,
      hardLimitTokens,
    },
    candidates: data.candidates.map(normalizeCandidate),
  }
}

import { existsSync, readFileSync, writeFileSync } from 'node:fs'
