export type ImportOptions = {
  title: string
  objective: string
  outFile: string
  softLimitTokens: number
  hardLimitTokens: number
  readPaths: string[]
  logPaths: string[]
  searchPatterns: string[]
  searchRoot: string
}

const DEFAULT_REPO_REVIEW_READ_PATHS = [
  'README.md',
  'package.json',
  'SECURITY.md',
  'CONTRIBUTING.md',
  '.gitignore',
  'eslint.config.js',
  'tsconfig.json',
  'docs/architecture.md',
  'src/cli.ts',
  'src/context-governor.ts',
  'src/rules.ts',
  'src/config.ts',
  'src/input.ts',
  'src/importer.ts',
  'src/claude.ts',
  'src/report.ts',
  '.github/workflows/ci.yml',
  '.github/workflows/secret-scan.yml',
]

const DEFAULT_REPO_REVIEW_SEARCH_PATTERNS = [
  'token',
  'claude',
  'security',
  'review',
]

function createCandidate(args: {
  id: string
  kind: ContextCandidate['kind']
  priority: ContextCandidatePriority
  content: string
  source: string
}): ContextCandidate {
  return {
    id: args.id,
    kind: args.kind,
    priority: args.priority,
    content: args.content,
    tokenEstimate: estimateTokens(args.content),
    metadata: { source: args.source },
  }
}

function readSearchResults(pattern: string, searchRoot: string): string {
  const result = spawnSync(
    'rg',
    ['-n', '--no-heading', pattern, searchRoot],
    { encoding: 'utf8' },
  )

  if (result.status !== 0 && result.status !== 1) {
    throw new Error(result.stderr || `rg failed for pattern: ${pattern}`)
  }

  return result.stdout.trim()
}

export function buildImportedScenario(options: ImportOptions): BenchmarkScenario {
  const candidates: ContextCandidate[] = [
    {
      id: 'objective',
      kind: 'other',
      priority: 'critical',
      content: options.objective,
      tokenEstimate: estimateTokens(options.objective),
      metadata: { source: 'objective' },
    },
  ]

  for (const filePath of options.readPaths) {
    const absolutePath = resolve(filePath)
    const content = readFileSync(absolutePath, 'utf8')
    candidates.push(
      createCandidate({
        id: `read-${basename(filePath).replace(/\W+/g, '-').toLowerCase()}`,
        kind: 'file_read',
        priority: 'high',
        content,
        source: filePath,
      }),
    )
  }

  for (const filePath of options.logPaths) {
    const absolutePath = resolve(filePath)
    const content = readFileSync(absolutePath, 'utf8')
    candidates.push(
      createCandidate({
        id: `log-${basename(filePath).replace(/\W+/g, '-').toLowerCase()}`,
        kind: 'shell_output',
        priority: 'medium',
        content,
        source: filePath,
      }),
    )
  }

  for (const pattern of options.searchPatterns) {
    const content = readSearchResults(pattern, options.searchRoot)
    if (!content) continue
    candidates.push(
      createCandidate({
        id: `search-${pattern.replace(/\W+/g, '-').toLowerCase()}`,
        kind: 'search_result',
        priority: 'medium',
        content,
        source: `rg ${pattern}`,
      }),
    )
  }

  return {
    id: options.title.toLowerCase().replace(/\W+/g, '-'),
    title: options.title,
    description: `Imported scenario for ${options.title}`,
    budget: {
      softLimitTokens: options.softLimitTokens,
      hardLimitTokens: options.hardLimitTokens,
    },
    candidates,
  }
}

function getExistingPaths(paths: string[], rootDir: string): string[] {
  return paths.filter(filePath => existsSync(resolve(rootDir, filePath)))
}

export function buildRepoReviewImportOptions(args: {
  rootDir: string
  title?: string
  objective?: string
  outFile?: string
  softLimitTokens?: number
  hardLimitTokens?: number
}): ImportOptions {
  const rootDir = resolve(args.rootDir)

  return {
    title: args.title ?? 'Repository Review',
    objective:
      args.objective ??
      'Review this repository for architecture, maintainability, usability friction, and security. Return concise findings.',
    outFile: resolve(rootDir, args.outFile ?? './acg-repo-review.json'),
    softLimitTokens: args.softLimitTokens ?? 2600,
    hardLimitTokens: args.hardLimitTokens ?? 3600,
    readPaths: getExistingPaths(DEFAULT_REPO_REVIEW_READ_PATHS, rootDir).map(
      filePath => resolve(rootDir, filePath),
    ),
    logPaths: [],
    searchPatterns: DEFAULT_REPO_REVIEW_SEARCH_PATTERNS,
    searchRoot: rootDir,
  }
}

export function writeImportedScenario(options: ImportOptions): BenchmarkScenario {
  const scenario = buildImportedScenario(options)
  writeFileSync(options.outFile, `${JSON.stringify(scenario, null, 2)}\n`, 'utf8')
  return scenario
}

import { spawnSync } from 'node:child_process'

import { runScenario } from './benchmark.js'
import type {
  BenchmarkScenario,
  ClaudeComparisonResult,
  ClaudePromptMode,
  ClaudeUsageResult,
} from './types.js'

function buildPrompt(
  task: string,
  contextBlocks: string[],
  mode: ClaudePromptMode,
): string {
  const blocks = contextBlocks.map((block, index) => {
    return `Context Block ${index + 1}:\n${block}`
  })

  const instructions =
    mode === 'benchmark'
      ? [
          'You are being used only for a token benchmark.',
          'Do not perform extra analysis.',
          'Read the provided task and context.',
          'Reply with exactly: OK',
        ]
      : [
          'Review the provided project context.',
          'Focus on architecture, maintainability, and security.',
          'Be concise and concrete.',
          'Output 3-6 short bullet points.',
        ]

  return [
    ...instructions,
    '',
    `Task:\n${task}`,
    '',
    ...blocks,
  ].join('\n')
}

function parseClaudeResult(stdout: string): ClaudeUsageResult {
  let parsed: {
    result?: string
    total_cost_usd?: number
    modelUsage?: Record<
      string,
      {
        inputTokens: number
        outputTokens: number
        cacheReadInputTokens: number
        cacheCreationInputTokens: number
      }
    >
    usage?: {
      input_tokens: number
      cache_creation_input_tokens?: number
      cache_read_input_tokens?: number
      output_tokens: number
    }
  }

  try {
    parsed = JSON.parse(stdout) as typeof parsed
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error)
    throw new Error(
      `Failed to parse Claude JSON output: ${message}. First 200 chars: ${stdout.slice(0, 200)}`,
    )
  }

  const usage = parsed.usage
  if (!usage) {
    throw new Error('Claude result did not contain usage data')
  }

  const model = parsed.modelUsage ? Object.keys(parsed.modelUsage)[0] : undefined

  return {
    inputTokens: usage.input_tokens,
    cacheCreationInputTokens: usage.cache_creation_input_tokens ?? 0,
    cacheReadInputTokens: usage.cache_read_input_tokens ?? 0,
    outputTokens: usage.output_tokens,
    totalCostUsd: parsed.total_cost_usd,
    model,
    rawResult: parsed.result ?? '',
  }
}

export function runClaudeBenchmark(
  scenario: BenchmarkScenario,
  options?: {
    claudeBin?: string
    model?: string
    mode?: ClaudePromptMode
    permissionMode?: 'default' | 'bypassPermissions'
  },
): ClaudeComparisonResult {
  const claudeBin = options?.claudeBin ?? 'claude'
  const mode = options?.mode ?? 'benchmark'
  const optimized = runScenario(scenario)
  const task = scenario.candidates[0]?.content ?? scenario.title
  const baselinePrompt = buildPrompt(
    task,
    scenario.candidates.map(candidate => candidate.content),
    mode,
  )
  const optimizedPrompt = buildPrompt(task, optimized.finalContext, mode)

  const runClaude = (prompt: string): ClaudeUsageResult => {
    const args = ['-p', '--output-format', 'json']
    if (options?.permissionMode) {
      args.push('--permission-mode', options.permissionMode)
    }
    if (options?.model) {
      args.push('--model', options.model)
    }

    const result = spawnSync(claudeBin, args, {
      input: prompt,
      encoding: 'utf8',
    })

    if (result.status !== 0) {
      throw new Error(result.stderr || `Claude exited with code ${result.status}`)
    }

    return parseClaudeResult(result.stdout)
  }

  const baseline = runClaude(baselinePrompt)
  const optimizedUsage = runClaude(optimizedPrompt)

  const baselineTotal =
    baseline.inputTokens +
    baseline.cacheCreationInputTokens +
    baseline.cacheReadInputTokens +
    baseline.outputTokens
  const optimizedTotal =
    optimizedUsage.inputTokens +
    optimizedUsage.cacheCreationInputTokens +
    optimizedUsage.cacheReadInputTokens +
    optimizedUsage.outputTokens

  return {
    baseline,
    optimized: optimizedUsage,
    savedInputTokens: baseline.inputTokens - optimizedUsage.inputTokens,
    savedCacheCreationTokens:
      baseline.cacheCreationInputTokens -
      optimizedUsage.cacheCreationInputTokens,
    savedCacheReadTokens:
      baseline.cacheReadInputTokens - optimizedUsage.cacheReadInputTokens,
    savedTotalTokens: baselineTotal - optimizedTotal,
  }
}

export function runClaudeReviewComparison(
  scenario: BenchmarkScenario,
  options?: {
    claudeBin?: string
    model?: string
    permissionMode?: 'default' | 'bypassPermissions'
  },
): ClaudeComparisonResult {
  return runClaudeBenchmark(scenario, {
    ...options,
    mode: 'review',
  })
}

import { writeFileSync } from 'node:fs'

import { runClaudeReviewComparison } from './claude.js'
import { parseScenarioFile } from './input.js'

function extractBullets(text: string): string[] {
  return text
    .split('\n')
    .map(line => line.trim())
    .filter(line => line.startsWith('- ') || line.startsWith('* '))
    .map(line => line.slice(2).trim())
}

function normalizeFinding(text: string): string {
  return text
    .toLowerCase()
    .replace(/[`*_:#()[\].,]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim()
}

const FINDING_TOPICS: Record<string, string[]> = {
  token_estimation: ['estimateTokens', 'token estimation', 'tokenizer', 'hardcoded / 4'],
  claude_api_surface: ['claude.ts', 'public api', 'public index', 'spawnsync', 'claude binary'],
  permissions: ['bypasspermissions', 'permission-mode', 'permission system'],
  prioritization: ['priority', 'comparecandidates', 'ranking'],
  architecture_gap: ['architecture', 'contextartifactstore', 'surrogatebuilder', 'implementation gap'],
  parsing_validation: ['json.parse', 'validation', 'schema', 'malformed', 'external output'],
  testing: ['test', 'stale dist', 'pre-test build'],
  linting: ['eslint', 'typescript-eslint', 'lint'],
  ci_runtime: ['ci', 'github actions', 'node 20', 'engines'],
  config_validation: ['mergegovernorconfig', 'nan', 'hardlimittokens', 'softlimittokens'],
}

function inferTopics(text: string): string[] {
  const normalized = normalizeFinding(text)

  return Object.entries(FINDING_TOPICS)
    .filter(([, patterns]) =>
      patterns.some(pattern => normalized.includes(normalizeFinding(pattern))),
    )
    .map(([topic]) => topic)
}

function computeOverlap(
  baselineFindings: string[],
  optimizedFindings: string[],
): {
  shared: string[]
  baselineOnly: string[]
  optimizedOnly: string[]
  sharedTopics: string[]
  baselineOnlyTopics: string[]
  optimizedOnlyTopics: string[]
} {
  const optimizedNormalized = new Map(
    optimizedFindings.map(item => [normalizeFinding(item), item]),
  )
  const baselineNormalized = new Map(
    baselineFindings.map(item => [normalizeFinding(item), item]),
  )

  const shared: string[] = []
  const baselineOnly: string[] = []
  const optimizedOnly: string[] = []

  for (const item of baselineFindings) {
    if (optimizedNormalized.has(normalizeFinding(item))) {
      shared.push(item)
    } else {
      baselineOnly.push(item)
    }
  }

  for (const item of optimizedFindings) {
    if (!baselineNormalized.has(normalizeFinding(item))) {
      optimizedOnly.push(item)
    }
  }

  const baselineTopics = new Set(baselineFindings.flatMap(inferTopics))
  const optimizedTopics = new Set(optimizedFindings.flatMap(inferTopics))

  const sharedTopics = [...baselineTopics].filter(topic => optimizedTopics.has(topic))
  const baselineOnlyTopics = [...baselineTopics].filter(
    topic => !optimizedTopics.has(topic),
  )
  const optimizedOnlyTopics = [...optimizedTopics].filter(
    topic => !baselineTopics.has(topic),
  )

  return {
    shared,
    baselineOnly,
    optimizedOnly,
    sharedTopics,
    baselineOnlyTopics,
    optimizedOnlyTopics,
  }
}

export function writeClaudeReviewReport(
  scenarioPath: string,
  outFile: string,
): string {
  const scenario = parseScenarioFile(scenarioPath)
  const result = runClaudeReviewComparison(scenario)
  const baselineFindings = extractBullets(result.baseline.rawResult)
  const optimizedFindings = extractBullets(result.optimized.rawResult)
  const overlap = computeOverlap(baselineFindings, optimizedFindings)

  const markdown = [
    `# Claude Review Report`,
    ``,
    `Scenario: ${scenario.title}`,
    ``,
    `## Usage`,
    ``,
    `- Saved input tokens: ${result.savedInputTokens}`,
    `- Saved cache creation tokens: ${result.savedCacheCreationTokens}`,
    `- Saved cache read tokens: ${result.savedCacheReadTokens}`,
    `- Saved total tokens: ${result.savedTotalTokens}`,
    `- Baseline cost USD: ${result.baseline.totalCostUsd ?? 'unknown'}`,
    `- Optimized cost USD: ${result.optimized.totalCostUsd ?? 'unknown'}`,
    ``,
    `## Overlap Summary`,
    ``,
    `- Shared findings: ${overlap.shared.length}`,
    `- Baseline-only findings: ${overlap.baselineOnly.length}`,
    `- Optimized-only findings: ${overlap.optimizedOnly.length}`,
    ``,
    `## Topic Overlap`,
    ``,
    `- Shared topics: ${overlap.sharedTopics.length}`,
    ...(overlap.sharedTopics.length > 0
      ? overlap.sharedTopics.map(topic => `- ${topic}`)
      : ['- None']),
    `- Baseline-only topics: ${overlap.baselineOnlyTopics.length}`,
    ...(overlap.baselineOnlyTopics.length > 0
      ? overlap.baselineOnlyTopics.map(topic => `- ${topic}`)
      : ['- None']),
    `- Optimized-only topics: ${overlap.optimizedOnlyTopics.length}`,
    ...(overlap.optimizedOnlyTopics.length > 0
      ? overlap.optimizedOnlyTopics.map(topic => `- ${topic}`)
      : ['- None']),
    ``,
    `## Baseline-Only Findings`,
    ``,
    ...(overlap.baselineOnly.length > 0
      ? overlap.baselineOnly.map(item => `- ${item}`)
      : ['- None']),
    ``,
    `## Optimized-Only Findings`,
    ``,
    ...(overlap.optimizedOnly.length > 0
      ? overlap.optimizedOnly.map(item => `- ${item}`)
      : ['- None']),
    ``,
    `## Baseline Review`,
    ``,
    result.baseline.rawResult || '(empty)',
    ``,
    `## Optimized Review`,
    ``,
    result.optimized.rawResult || '(empty)',
    ``,
  ].join('\n')

  writeFileSync(outFile, markdown, 'utf8')
  return markdown
}

